# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, request, redirect, session, url_for
import requests
import json
import jwt
import urllib.parse

app = Flask(__name__)
app.secret_key = 'your-secret-key'

# OpenID Connect Configuration
OIDC_CONFIG = {
    'issuer': 'https://your-oidc-provider.com',
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

def get_oidc_config():
    response = requests.get(OIDC_CONFIG['issuer'] + '/.well-known/openid-configuration')
    return response.json()

@app.route('/')
def index():
    if 'user' in session:
        return f'Hello {session["user"]["name"]}! <a href="/logout">Logout</a>'
    return '<a href="/login">Login with OpenID Connect</a>'

@app.route('/login')
def login():
    config = get_oidc_config()
    auth_url = config['authorization_endpoint']
    
    params = {
        'response_type': 'code',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scope'],
        'state': 'random-state-value'
    }
    
    query_string = urllib.parse.urlencode(params)
    return redirect(f"{auth_url}?{query_string}")

@app.route('/callback')
def callback():
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return 'Authorization code not found', 400
    
    config = get_oidc_config()
    
    token_url = config['token_endpoint']
    
    token_data = {
        'grant_type': 'authorization_code',
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri']
    }
    
    response = requests.post(token_url, data=token_data)
    token_response = response.json()
    
    id_token = token_response.get('id_token')
    if not id_token:
        return 'ID token not found', 400
    
    # Decode JWT without verification for simplicity
    try:
        decoded_token = jwt.decode(id_token, options={"verify_signature": False})
    except Exception as e:
        return f'Failed to decode token: {str(e)}', 400
    
    # Store user info in session
    session['user'] = {
        'sub': decoded_token.get('sub'),
        'name': decoded_token.get('name'),
        'email': decoded_token.get('email'),
        'preferred_username': decoded_token.get('preferred_username')
    }
    
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)